import React, { useState } from "react";
import styles from "./nav-bar.module.css";
import NavButton from "../nav-button";
import MegaMenu from "../mega-menu";

const NavBar = () => {
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);

  function toggleDropdown(openDropdown: string) {
    setActiveDropdown(activeDropdown === openDropdown ? null : openDropdown);
  }

  const obj1 = {
    title: "Discovery",
    content: ["Item 1", "Item 2", "Item 3"],
  };

  const dropDownObjectEx = [obj1];

  return (
    <>
      <div className={styles.nav__bar}>
        <NavButton
          text="Discovery"
          imgSrc="/images/ChevronDown.png"
          handleClick={() => toggleDropdown("Discovery")}
        />
        <NavButton text="About" isLink={true} />
        <NavButton text="Contact us" isLink={true} />
      </div>

    </>
  );
};

export default NavBar;


